class MedianFinder {
    constructor() {
        this.lo = new MaxHeap();
        this.hi = new MinHeap();
    }
    addNum(num) {
        this.lo.push(num);
        this.hi.push(this.lo.pop());
        if (this.hi.size() > this.lo.size()) {
            this.lo.push(this.hi.pop());
        }
    }
    findMedian() {
        if (this.lo.size() > this.hi.size()) {
            return this.lo.peek();
        }
        const total = this.lo.peek() + this.hi.peek();
        return total / 2;
    }
}

class Heap {
    constructor(cmp) { this.h = []; this.cmp = cmp; }
    size() { return this.h.length; }
    peek() { return this.h[0]; }
    push(v) {
        const h = this.h;
        h.push(v);
        let i = h.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (this.cmp(h[i], h[p]) < 0) { [h[i], h[p]] = [h[p], h[i]]; i = p; } else break;
        }
    }
    pop() {
        const h = this.h;
        const top = h[0];
        const last = h.pop();
        if (h.length > 0) {
            h[0] = last;
            let i = 0;
            const n = h.length;
            while (true) {
                let s = i;
                const l = 2 * i + 1, r = 2 * i + 2;
                if (l < n && this.cmp(h[l], h[s]) < 0) s = l;
                if (r < n && this.cmp(h[r], h[s]) < 0) s = r;
                if (s === i) break;
                [h[i], h[s]] = [h[s], h[i]]; i = s;
            }
        }
        return top;
    }
}

class MinHeap extends Heap { constructor() { super((a, b) => a - b); } }
class MaxHeap extends Heap { constructor() { super((a, b) => b - a); } }
